SELECT DISTINCT su.id AS id, su.student_id AS studentId, su.name AS studentName, su.grade AS grade, c.name AS className, m.name AS majorName FROM student_users su LEFT JOIN class c ON su.class_id = c.id LEFT JOIN major m ON su.major_id = m.id INNER JOIN student_course sc ON su.id = sc.student_user_id
sc.course_id IN
#{courseId}
AND su.name LIKE CONCAT('%', #{searchName}, '%')
AND su.class_id = #{classId}
ORDER BY su.student_id ASC

SELECT su.id, su.student_user_id AS studentUserId, su.name, su.gender, su.grade, su.major_id AS majorId, su.class_id AS classId, c.name AS className, m.name AS majorName, su.status, sis.status AS internshipStatus, cu.company_name AS companyName FROM student_users su LEFT JOIN class c ON su.class_id = c.id LEFT JOIN major m ON su.major_id = m.id LEFT JOIN student_internship_status sis ON su.id = sis.student_id LEFT JOIN company_users cu ON sis.company_id = cu.id
su.class_id IN
#{classId}
AND su.name LIKE CONCAT('%', #{searchName}, '%')
AND m.name = #{major}
AND su.grade = #{grade}
AND sis.status = #{status}
AND cu.company_name LIKE CONCAT('%', #{companyName}, '%')
ORDER BY su.class_id ASC, su.student_user_id ASC
